import {
  type FocusEvent as ReactFocusEvent,
  type PropsWithChildren,
  type ReactElement,
} from 'react';

import { DotMenuIcon } from '@dynatrace/strato-icons';

import { seriesButton } from './ChartLegendSeriesActions.sty.js';
import { Button } from '../../../../../../../buttons/button/Button.js';
import { Menu } from '../../../../../../../navigation/menu/Menu.js';
import { useCustomSeriesActions } from '../../../../../hooks/useCustomSeriesActions.js';
import { SeriesActionsTemplate } from '../../../../../types/series-actions-template.js';
import { renderMenuActionChildren } from '../../../../../utils/render-menu-action-children.js';

export interface LegendSeriesActionsProps {
  onFocus: () => void;
  onMouseEnter: () => void;
  onMouseLeave: () => void;
  /** Disables the menu trigger. */
  disabled?: boolean;
  /** Makes the actions button visible or hidden **/
  visible?: boolean;
  onOpenChange?: (open: boolean) => void;
  isOpen: boolean;
  onBlur: () => void;
  /** Default actions to display **/
  defaultActions?: ReactElement<PropsWithChildren>;
  /** Custom series actions to display **/
  actions?: SeriesActionsTemplate;
}

/**
 * LegendSeriesActions component.
 */
export const ChartLegendSeriesActions = (props: LegendSeriesActionsProps) => {
  const {
    disabled,
    onOpenChange,
    isOpen,
    visible = false,
    onFocus,
    onBlur,
    onMouseEnter,
    onMouseLeave,
    defaultActions,
    actions,
  } = props;

  const handleFocus = (event: ReactFocusEvent) => {
    event.stopPropagation();
    onFocus();
  };
  const customActions = useCustomSeriesActions(actions, isOpen);

  return (
    <Menu onOpenChange={onOpenChange}>
      <Menu.Trigger>
        <Button
          data-testid="legend-more-actions-button"
          variant="default"
          disabled={disabled}
          onFocus={handleFocus}
          onBlur={onBlur}
          onMouseEnter={onMouseEnter}
          onMouseLeave={onMouseLeave}
          className={seriesButton({ visible: visible })}
        >
          <Button.Prefix>
            <DotMenuIcon size="small" />
          </Button.Prefix>
        </Button>
      </Menu.Trigger>
      {!disabled && isOpen && (
        <Menu.Content data-testid="menu-content">
          {defaultActions ? renderMenuActionChildren(defaultActions) : null}
          {customActions ? (
            <div data-dt-children-name="LegendSeriesItems">
              {renderMenuActionChildren(customActions.props.children)}
            </div>
          ) : null}
        </Menu.Content>
      )}
    </Menu>
  );
};

ChartLegendSeriesActions['displayName'] = 'LegendSeriesActions';
